import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class ContractCreationTransaction {
 public static String contractCreationTransaction(String senderAddress, int nonce, String bytecode) throws NoSuchAlgorithmException {
 // Calculate contract address
 MessageDigest md = MessageDigest.getInstance("SHA3-256");
 byte[] hashBytes = md.digest((senderAddress + nonce).getBytes());
 String contractAddress = bytesToHex(hashBytes).substring(24);
 // Deploy contract
 // deployContract(contractAddress, bytecode); // This function is not implemented here
 // Return contract address
 return contractAddress;
 }

 private static String bytesToHex(byte[] bytes) {
 StringBuilder result = new StringBuilder();
 for (byte b : bytes) {
 result.append(String.format("%02x", b));
 }
 return result.toString();
 }
}
